import { useState } from 'react';
import api from '../api/client';
import LoadingSpinner from '../components/LoadingSpinner';

function HospitalLocator() {
  const [city, setCity] = useState('');
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(false);

  const search = async () => {
    setLoading(true);
    const { data } = await api.get('/hospitals', { params: { city } });
    setItems(data);
    setLoading(false);
  };

  return (
    <div className="container py-4">
      <h2>Hospital Locator</h2>
      <div className="d-flex gap-2 my-3">
        <input className="form-control" placeholder="Enter city" value={city} onChange={(e) => setCity(e.target.value)} />
        <button className="btn btn-danger" onClick={search}>Search</button>
      </div>
      {loading && <LoadingSpinner />}
      <div className="list-group">
        {items.map((h) => (
          <div key={h.id} className="list-group-item">
            <h6 className="mb-1">{h.name}</h6>
            <small>{h.address}, {h.city} | {h.phone}</small>
          </div>
        ))}
      </div>
      <div className="ratio ratio-16x9 mt-4">
        <iframe
          title="map"
          src="https://maps.google.com/maps?q=India&t=&z=5&ie=UTF8&iwloc=&output=embed"
          allowFullScreen
        />
      </div>
    </div>
  );
}

export default HospitalLocator;
